import React from "react";
import s from "./MyDialogs.module.css";

import { updateNewMessageBodyCreator,sendMessageCreator } from "../../redux/mydialogs-reducer";
import MyDialogs from "./MyDialogs";
import {connect} from "react-redux";

let mapStateToProps = (state) => {
return {
    mydialogsPage:state.mydialogsPage
}
}

let mapDispatchToProps = (dispatch) => {
    return{
        updateNewMessageBody: (body) => {
        dispatch(updateNewMessageBodyCreator(body))
    },
        sendMessage: () => {
        dispatch(sendMessageCreator())
    }
}
}






export default connect(mapStateToProps, mapDispatchToProps)(MyDialogs);