const FOLLOW = "FOLLOW";


const UNFOLLOW = "UNFOLLOW";
const SET_USERS = "SET_USERS";

let initialState = {
   
      users: [
        { id: 1, photoUrl: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRNQoZ_eF4ZVub99aUtKo8WZSBSLWEiyr99UQ&s", followed: true, fullName: "Dmitry", status: "I am a boss", location: { city: "Minsk", country: "Belarus" }, email: "dmitry@example.com" },
        { id: 2, photoUrl: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRNQoZ_eF4ZVub99aUtKo8WZSBSLWEiyr99UQ&s", followed: true, fullName: "Jane Smith", status: "I am a user", location: { city: "New York", country: "USA" }, email: "jane@example.com" },
        { id: 3, photoUrl: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRNQoZ_eF4ZVub99aUtKo8WZSBSLWEiyr99UQ&s", followed: false, fullName: "Bob Johnson", status: "I am a user", location: { city: "London", country: "UK" }, email: "bob@example.com" },
        { id: 4, photoUrl: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRNQoZ_eF4ZVub99aUtKo8WZSBSLWEiyr99UQ&s", followed: false, fullName: "Alice Williams", status: "I am a user", location: { city: "Tokyo", country: "Japan" }, email: "alice@example.com" },
      ]
    }

 const othersReducer = (state =initialState, action) => {
 switch(action.type) {
  case FOLLOW:
     return {...state, 
       // users:[...state.users],
        users: state.users.map(u => {
          if(u.id ===action.userId) {
            return {...u, followed: true};
          }
          return u;
        } )
      };
     
   case UNFOLLOW:
   return {...state, 
       // users:[...state.users],
        users: state.users.map(u => {
          if(u.id ===action.userId) {
            return {...u, followed: false};
          }
          return u;
        } )
      };
      case SET_USERS:
        return {...state, users: [...state.users, ...action.users]};
    
        default:
          return state;
 }
  };

  

  export const followAC = (userId) => ({ type: FOLLOW, userId });
  
  export const unfollowAC = (userId) => ({
    type: UNFOLLOW, userId});
     export const setUsersAC = (userId) => ({
    type: SET_USERS, userId});

export default othersReducer;

  