
import { usersAPI } from "../api/api";
import {updateObjectArray} from "../utils/validators/object-helpers"

const FOLLOW = "FOLLOW";
const UNFOLLOW = "UNFOLLOW";
const SET_USERS = "SET-USERS";
const SET_CURRENT_PAGE = "SET-CURRENT-PAGE";
const SET_TOTAL_USERS_COUNT = "SET-TOTAL-USERS-COUNT";
const TOGGLE_IS_FETCHING = "TOGGLE-IS-FETCHING";
const TOGGLE_IS_FOLLOWING_PROGRESS = "TOGGLE_IS_FOLLOWING_PROGRESS";



let initialState = {
   
    users: [],
    pageSize: 10,
    totalUsersCount: 20,
    currentPage: 1,
     isFetching: false,
     followingInProgress: []  

     
    
}
 const userReducer = (state =initialState, action) => {
switch(action.type) {
  //case "FAKE":return {...state, fake:state.currentPage.fake+1}
  case FOLLOW:
   return {...state,
      users: updateObjectArray(state.users, action.userId,"id",{followed:true}),
      // users: state.users.map(u => {
      //   return u.id === action.userId ? {...u, followed: true} : u
      // })
    };
  case UNFOLLOW:
    return {...state,
       users: updateObjectArray(state.users, action.userId,"id",{followed:false})
      // users: state.users.map(u => {
      //   return u.id === action.userId ?  {...u, followed: false} : u
      // })
    };
    case SET_USERS:
      return {...state,  users: action.users};
   
     
  case SET_CURRENT_PAGE:
    return {...state, currentPage: action.currentPage};
  case SET_TOTAL_USERS_COUNT:
    return {...state, totalUsersCount: action.totalCount};
  case TOGGLE_IS_FETCHING:
    return {...state, isFetching: action.isFetching};
  case TOGGLE_IS_FOLLOWING_PROGRESS:
    return {
    ...state,
    followingInProgress: action.isFetching
      ? [...state.followingInProgress, action.userId]   // добавить id
      : state.followingInProgress.filter(id => id !== action.userId) // убрать id
  };
   default:
          return state;
  }
  
  };

  export const followSucceeded = (userId) => ({ type: FOLLOW, userId });
  export const unfollowSucceeded = (userId) => ({ type: UNFOLLOW, userId });
  export const setUsers = (users) => ({ type: SET_USERS, users });
  export const setCurrentPage = (currentPage) => ({ type: SET_CURRENT_PAGE, currentPage }); 
export const setTotalUsersCount = (totalCount) => ({ type: SET_TOTAL_USERS_COUNT, totalCount });
 export const toggleIsFetching = (isFetching) => ({ type: TOGGLE_IS_FETCHING, isFetching }); 
export const toggleFollowingProgress = (isFetching, userId) => ({
  type: TOGGLE_IS_FOLLOWING_PROGRESS,
  isFetching,
  userId
});

export const requestUsers  = (currentPage, pageSize) => {
  return async (dispatch) => {
    dispatch(setCurrentPage(currentPage));
    dispatch(toggleIsFetching(true));
 let data = await usersAPI.getUsers(currentPage, pageSize)
 
      dispatch(toggleIsFetching(false));
      dispatch(setUsers(data.items));
      dispatch(setTotalUsersCount(data.totalCount));
    
  };
} 

const followUnfollowFlow = async(dispatch,userId, apiMethod,actionCreator) =>{
    dispatch(toggleFollowingProgress(true, userId));
    let response = await apiMethod(userId)
    
      if (response.resultCode === 0) {
        dispatch(actionCreator(userId));
      }
      dispatch(toggleFollowingProgress(false, userId));
  
}


export const follow = (userId) => {
  return async(dispatch) => {
 
    followUnfollowFlow(dispatch,userId, usersAPI.follow.bind(usersAPI),followSucceeded) 

  };
}
export const unfollow = (userId) => {
  return async(dispatch) => {
   
     followUnfollowFlow(dispatch,userId, usersAPI.unfollow.bind(usersAPI),unfollowSucceeded);

 
  
  };
} 
export default userReducer;